create procedure [dbo].[CREATE_B2BA] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.B2BA','U') IS NOT NULL DROP TABLE B2BA CREATE TABLE B2BA ( [GSTIN/UIN] varchar(32), [Invoice Number] varchar(21), [Invoice date] datetime, [Revised Invoice Number] varchar(21), [Revised Invoice date] datetime, [Total Invoice Value] decimal, [Place Of Supply] varchar(2), [Reverse Charge] varchar(1), [Provisional Assessment] varchar(1), [E-Commerce GSTIN] varchar(1), [Category] varchar(1), [HSN/SAC of Supply] varchar(16), [Total Taxable Value] decimal, [IGST Rate] decimal, [IGST Amount] decimal, [CGSTRate] decimal, [CGST Amount] decimal,  [SGST Rate] decimal, [SGST Amount] decimal, [CESS Rate] decimal, [CESS Amount] decimal) Set @Tablename='B2BA' Select @Tablename